import React, { useState } from "react";

function App() {
  const [songs, setSongs] = useState([]);

  const musicData = {
    Happy: ["Shape of You", "Believer", "Perfect"],
    Sad: ["Someone Like You", "Let Her Go", "Fix You"],
    Relaxed: ["Closer", "Memories", "Photograph"]
  };

  const showSongs = (mood) => {
    setSongs(musicData[mood]);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "30px" }}>
      <h1>Mood-Based Music Recommender</h1>

      <button onClick={() => showSongs("Happy")}>
        Happy
      </button>

      <button onClick={() => showSongs("Sad")}>
        Sad
      </button>

      <button onClick={() => showSongs("Relaxed")}>
        Relaxed
      </button>

      <h2>Recommended Songs</h2>

      <ul>
        {songs.map((song, index) => (
          <li key={index}>{song}</li>
        ))}
      </ul>
    </div>
  );
}

export default App;
